const body = $input.first().json.body || $input.first().json;
const mime = body.mime_type || 'application/pdf';
const isImage = mime.startsWith('image/');
const aiModel = isImage ? 'Mistral Vision (pixtral-12b-2409)' : 'Mistral Small (mistral-small-latest)';
console.log('Document recu:', body.nom_fichier, '| Modele IA:', aiModel);
return [{ json: {
  nom_fichier: body.nom_fichier || 'document',
  mime_type: mime,
  ai_model: aiModel,
  is_image: isImage,
  received_at: new Date().toISOString(),
  // donnees deja extraites par le backend
  type_document: body.type_document,
  fournisseur: body.fournisseur,
  numero_document: body.numero_document,
  date_document: body.date_document || '',
  montant_ht: body.montant_ht || '0',
  montant_tva: body.montant_tva || '0',
  montant_ttc: body.montant_ttc || '0',
  score_confiance: body.score_confiance || 0,
  modele_ia: body.modele_ia || aiModel,
  lignes: body.lignes || []
}}];

const d = $input.first().json;
const typeLabels = { 'facture':'Facture','devis':'Devis','bon_livraison':'Bon de Livraison','bon_commande':'Bon de Commande','avoir':'Avoir' };
const typeLabel = typeLabels[d.type_document] || d.type_document || 'Inconnu';
const confiance = Math.round((d.score_confiance||0)*100);
const niveau = confiance>=85?'Eleve':confiance>=60?'Moyen':'Faible';
console.log('Classification Mistral AI:', typeLabel, confiance+'%');
return [{ json: { ...d, type_label: typeLabel, confiance_pct: confiance, confiance_niveau: niveau } }];

const d = $input.first().json;
console.log('Resultat classification valide:', d.type_label, d.confiance_pct+'%', d.confiance_niveau);
return [{ json: d }];

const d = $input.first().json;
const lignes = d.lignes || [];
const totalTTC = lignes.reduce((acc,l) => acc + Number(l.montant_ttc||0), 0);
console.log('Extraction Mistral AI:', lignes.length, 'articles | TTC:', totalTTC.toFixed(3), 'TND');
return [{ json: { ...d, nb_lignes: lignes.length, montant_ttc: d.montant_ttc || totalTTC.toFixed(3), extraction_moteur: d.is_image ? 'Mistral Vision (pixtral-12b-2409)' : 'Mistral Small (mistral-small-latest)' } }];

const d = $input.first().json;
console.log('Extraction complete:', d.nb_lignes, 'articles | Moteur:', d.extraction_moteur);
return [{ json: d }];

const d = $input.first().json;
const lignes = d.lignes || [];

// Couleur badge confiance
const badgeColor = d.confiance_pct >= 85 ? '#2e7d32' : d.confiance_pct >= 60 ? '#e65100' : '#c62828';
const badgeBg    = d.confiance_pct >= 85 ? '#e8f5e9' : d.confiance_pct >= 60 ? '#fff3e0' : '#ffebee';

// Tableau articles
let articlesHtml = '';
if (lignes.length > 0) {
  const rows = lignes.map((l, i) => {
    const pu  = Number(l.prix_unitaire || 0);
    const qte = Number(l.quantite || 1);
    const rem = Number(l.remise || 0);
    const tva = Number(l.tva || 0);
    const ttc = Number(l.montant_ttc || pu * qte * (1-rem/100) * (1+tva/100));
    return `<tr style="background:${i%2===0?'#fff':'#f8f9ff'}">`
      + `<td style="padding:9px 14px;border:1px solid #e8e8e8;font-weight:600;color:#1a1a2e">${l.designation||'N/A'}</td>`
      + `<td style="padding:9px 14px;border:1px solid #e8e8e8;font-family:monospace;font-size:11px;color:#1565c0;text-align:center">${l.reference||'-'}</td>`
      + `<td style="padding:9px 14px;border:1px solid #e8e8e8;text-align:center;font-weight:600">${qte}</td>`
      + `<td style="padding:9px 14px;border:1px solid #e8e8e8;text-align:right">${pu.toFixed(3)}</td>`
      + `<td style="padding:9px 14px;border:1px solid #e8e8e8;text-align:center;color:${rem>0?'#e65100':'#aaa'}">${rem>0?rem+'%':'-'}</td>`
      + `<td style="padding:9px 14px;border:1px solid #e8e8e8;text-align:center;color:#555">${tva>0?tva+'%':'-'}</td>`
      + `<td style="padding:9px 14px;border:1px solid #e8e8e8;text-align:right;font-weight:700;color:#1a1a2e">${ttc.toFixed(3)}</td>`
      + '</tr>';
  }).join('');
  articlesHtml =
    `<h3 style="color:#1a1a2e;font-size:15px;font-weight:700;margin:28px 0 14px;padding-bottom:8px;border-bottom:2px solid #f5c518">Articles Extraits par IA <span style="background:#1a1a2e;color:#f5c518;font-size:12px;padding:2px 10px;border-radius:20px;margin-left:8px">${lignes.length} ligne(s)</span></h3>`
    + '<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px">'
    + '<thead><tr style="background:#1a1a2e">'
    + '<th style="padding:11px 14px;color:#f5c518;text-align:left;border:1px solid #2a2a4a">Designation</th>'
    + '<th style="padding:11px 14px;color:#f5c518;text-align:center;border:1px solid #2a2a4a">Reference</th>'
    + '<th style="padding:11px 14px;color:#f5c518;text-align:center;border:1px solid #2a2a4a">Qte</th>'
    + '<th style="padding:11px 14px;color:#f5c518;text-align:right;border:1px solid #2a2a4a">Prix U. (TND)</th>'
    + '<th style="padding:11px 14px;color:#f5c518;text-align:center;border:1px solid #2a2a4a">Remise</th>'
    + '<th style="padding:11px 14px;color:#f5c518;text-align:center;border:1px solid #2a2a4a">TVA</th>'
    + '<th style="padding:11px 14px;color:#f5c518;text-align:right;border:1px solid #2a2a4a">TTC (TND)</th>'
    + '</tr></thead>'
    + `<tbody>${rows}</tbody>`
    + '<tfoot>'
    + `<tr style="background:#fff8e1"><td colspan="2" style="padding:11px 14px;font-weight:700;color:#555;border:1px solid #e0e0e0;font-size:12px">Moteur IA: ${d.extraction_moteur||'Mistral AI'}</td><td colspan="4" style="padding:11px 14px;font-weight:700;color:#1a1a2e;text-align:right;border:1px solid #e0e0e0">TOTAL HT</td><td style="padding:11px 14px;font-weight:700;color:#1a1a2e;text-align:right;border:1px solid #e0e0e0">${d.montant_ht} TND</td></tr>`
    + `<tr style="background:#f0f4ff"><td colspan="6" style="padding:11px 14px;font-weight:800;color:#1a1a2e;text-align:right;border:1px solid #e0e0e0;font-size:14px">TOTAL TTC</td><td style="padding:11px 14px;font-weight:800;font-size:16px;color:#1a1a2e;text-align:right;border:1px solid #e0e0e0">${d.montant_ttc} TND</td></tr>`
    + '</tfoot></table></div>';
} else {
  articlesHtml = '<p style="color:#888;font-style:italic;background:#f9f9f9;padding:16px;border-radius:8px;margin-top:20px">Aucun article extrait pour ce document.</p>';
}

// Predictions classification
const predsHtml = (d.predictions||[]).slice(0,3).map(p =>
  `<div style="display:flex;justify-content:space-between;align-items:center;padding:6px 0;border-bottom:1px solid #f0f0f0">`
  + `<span style="font-size:12px;color:#555">${p.type||p.label||'N/A'}</span>`
  + `<span style="font-size:12px;font-weight:700;color:#1565c0">${Math.round((p.score||0)*100)}%</span>`
  + '</div>'
).join('') || '<p style="color:#aaa;font-size:12px">N/A</p>';

const date = new Date().toLocaleString('fr-TN', { timeZone: 'Africa/Tunis' });
const subject = `[SPARKY] ${d.type_label} extrait - ${d.fournisseur||'Fournisseur inconnu'} - ${d.montant_ttc} TND`;

const htmlBody =
  '<div style="font-family:Arial,sans-serif;max-width:900px;margin:0 auto;background:#f5f5f5;padding:20px">'

  // HEADER
  + '<div style="background:#1a1a2e;padding:28px 32px;border-radius:14px 14px 0 0;text-align:center">'
  + '<h1 style="color:#f5c518;margin:0;font-size:28px;letter-spacing:-0.5px">SPARKY</h1>'
  + '<p style="color:rgba(255,255,255,.55);margin:6px 0 0;font-size:13px">Systeme Intelligent de Gestion Documentaire</p>'
  + '</div>'

  // PIPELINE STEPS
  + '<div style="background:#fff;padding:20px 32px;border:1px solid #e0e0e0">'
  + '<h2 style="color:#1a1a2e;font-size:16px;margin:0 0 16px;text-transform:uppercase;letter-spacing:1px">Pipeline IA Execute</h2>'
  + '<div style="display:flex;gap:0;margin-bottom:24px;overflow-x:auto">'
  + '<div style="flex:1;text-align:center;padding:12px 8px;background:#e8f5e9;border-radius:8px 0 0 8px;border:1px solid #c8e6c9"><div style="font-size:20px">📥</div><div style="font-size:10px;font-weight:700;color:#2e7d32;margin-top:4px">RECEPTION</div></div>'
  + '<div style="width:2px;background:#e0e0e0"></div>'
  + `<div style="flex:1;text-align:center;padding:12px 8px;background:#e3f2fd;border:1px solid #bbdefb"><div style="font-size:20px">🔍</div><div style="font-size:10px;font-weight:700;color:#1565c0;margin-top:4px">DETECTION</div><div style="font-size:9px;color:#888">${d.is_image?'Image':'PDF'}</div></div>`
  + '<div style="width:2px;background:#e0e0e0"></div>'
  + '<div style="flex:1;text-align:center;padding:12px 8px;background:#f3e5f5;border:1px solid #e1bee7"><div style="font-size:20px">🤖</div><div style="font-size:10px;font-weight:700;color:#6a1b9a;margin-top:4px">CLASSIFICATION</div><div style="font-size:9px;color:#888">Mistral AI</div></div>'
  + '<div style="width:2px;background:#e0e0e0"></div>'
  + '<div style="flex:1;text-align:center;padding:12px 8px;background:#fff3e0;border:1px solid #ffe0b2"><div style="font-size:20px">📊</div><div style="font-size:10px;font-weight:700;color:#e65100;margin-top:4px">EXTRACTION</div><div style="font-size:9px;color:#888">Mistral AI</div></div>'
  + '<div style="width:2px;background:#e0e0e0"></div>'
  + '<div style="flex:1;text-align:center;padding:12px 8px;background:#e8f5e9;border-radius:0 8px 8px 0;border:1px solid #c8e6c9"><div style="font-size:20px">✅</div><div style="font-size:10px;font-weight:700;color:#2e7d32;margin-top:4px">NOTIFICATION</div><div style="font-size:9px;color:#888">n8n</div></div>'
  + '</div>'

  // CLASSIFICATION RESULT
  + '<div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;margin-bottom:24px">'
  + '<div style="background:#f8f9ff;border-radius:12px;padding:20px;border-left:4px solid #1565c0">'
  + '<h3 style="margin:0 0 12px;color:#1a1a2e;font-size:14px">Classification IA</h3>'
  + `<div style="font-size:22px;font-weight:800;color:#1a1a2e;margin-bottom:8px">${d.type_label}</div>`
  + `<div style="display:inline-block;background:${badgeBg};color:${badgeColor};padding:4px 12px;border-radius:20px;font-size:12px;font-weight:700">Confiance: ${d.confiance_pct}% — ${d.confiance_niveau}</div>`
  + `<div style="margin-top:12px">${predsHtml}</div>`
  + '</div>'
  + '<div style="background:#f8f9ff;border-radius:12px;padding:20px;border-left:4px solid #f5c518">'
  + '<h3 style="margin:0 0 12px;color:#1a1a2e;font-size:14px">Informations Extraites</h3>'
  + `<table style="width:100%;font-size:13px"><tr><td style="padding:5px 0;color:#888">Fournisseur</td><td style="font-weight:700;color:#1a1a2e">${d.fournisseur||'N/A'}</td></tr><tr><td style="padding:5px 0;color:#888">Numero</td><td style="font-family:monospace;color:#1565c0">${d.numero_document||'N/A'}</td></tr><tr><td style="padding:5px 0;color:#888">Date</td><td style="color:#555">${d.date_document||'N/A'}</td></tr><tr><td style="padding:5px 0;color:#888">Montant HT</td><td style="font-weight:600">${d.montant_ht} TND</td></tr><tr><td style="padding:5px 0;color:#888">TVA</td><td style="color:#555">${d.montant_tva} TND</td></tr><tr><td style="padding:5px 0;color:#888">Montant TTC</td><td style="font-size:18px;font-weight:800;color:#1a1a2e">${d.montant_ttc} TND</td></tr></table>`
  + '</div></div>'

  // ARTICLES TABLE
  + articlesHtml

  + '</div>'

  // FOOTER
  + '<div style="background:#1a1a2e;padding:16px 32px;border-radius:0 0 14px 14px;text-align:center">'
  + `<p style="margin:0;color:rgba(255,255,255,.5);font-size:12px">SPARKY &mdash; Pipeline IA: Mistral AI (pixtral-12b + mistral-small) + n8n &mdash; ${date}</p>`
  + '</div>'
  + '</div>';

return [{ json: { subject, htmlBody, data: d } }];
